// PWM Generator - 8bit resolution
module RefModule(clk, reset, d, q);

    input clk;
    input reset;
    input d;
    output q;
    reg q;
    initial q = 0;

    always @(posedge clk)
        begin
            if (reset)
                q <= 0;
            else
                q <= d;
        end

endmodule
